import pytest

def test_close_account_unauthorised_caller_returns_403(
    api_client_owner_a, api_client_owner_b, account_owned_by_a
):
    account_id = account_owned_by_a["id"]
    resp = api_client_owner_b.post(
        f"/accounts/{account_id}/close",
        json={},
    )
    assert resp.status_code == 403, (
        f"Expected 403, got {resp.status_code}: {resp.text}"
    )
    detail = api_client_owner_a.get(f"/accounts/{account_id}")
    assert detail.json()["state"] == "active", (
        "Account must remain active after unauthorised close attempt"
    )
